INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000000,'I am Moorgoth the Death Hunter, stalker of the night and master of shadows. Would you like to browse my wares? * Uh, have we met before? Have you skirted the vast abyss of death? Have you stared entropy in the eye? Then you have met Moorgoth! Oh. Right. I guess you have, haven\'t you? I should have thought that through. I realize I didn\'t receive some divine calling to come here like some of the others, but I thought you would have need of my services. * Don\'t think I\'ve ever heard of "death hunters." There aren\'t a lot of us. That is to say, only a few. Okay, it\'s me and a couple buddies. But our ranks will grow! Our mandate is to patrol the shadowed roads of Azeroth and the realms beyond, keeping it safe for the innocent. And... Look, I\'m going to be honest. We just really, really think the dark rangers are amazing and we want to be near them. * Wait. What? I mean, just look at Velonara over there. She\'s like a dream! So brooding, so mysterious, so... dark. Have you worked with her before? What was it like? Say, have you two ever... Nevermind. Best not to know such things. The past is the past, and I need to focus on the future. My future with her. That\'s why I got all these black roses. I was going to give her a dozen, but that doesn\'t feel like quite enough to impress her. Say, would you talk to her? About me, I mean? Maybe bring her a gift? * I don\'t really want to get involved... That\'s fantastic! You\'re really the greatest. Oh, I hope Velonara has noticed me! * Well, it looks like I\'ll be speaking to her.','I am Moorgoth the Death Hunter, stalker of the night and master of shadows. Would you like to browse my wares? * Uh, have we met before? Have you skirted the vast abyss of death? Have you stared entropy in the eye? Then you have met Moorgoth! Oh. Right. I guess you have, haven\'t you? I should have thought that through. I realize I didn\'t receive some divine calling to come here like some of the others, but I thought you would have need of my services. * Don\'t think I\'ve ever heard of "death hunters." There aren\'t a lot of us. That is to say, only a few. Okay, it\'s me and a couple buddies. But our ranks will grow! Our mandate is to patrol the shadowed roads of Azeroth and the realms beyond, keeping it safe for the innocent. And... Look, I\'m going to be honest. We just really, really think the dark rangers are amazing and we want to be near them. * Wait. What? I mean, just look at Velonara over there. She\'s like a dream! So brooding, so mysterious, so... dark. Have you worked with her before? What was it like? Say, have you two ever... Nevermind. Best not to know such things. The past is the past, and I need to focus on the future. My future with her. That\'s why I got all these black roses. I was going to give her a dozen, but that doesn\'t feel like quite enough to impress her. Say, would you talk to her? About me, I mean? Maybe bring her a gift? * I don\'t really want to get involved... That\'s fantastic! You\'re really the greatest. Oh, I hope Velonara has noticed me! * Well, it looks like I\'ll be speaking to her.',0,0);
