INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000001,'Do not be alarmed. I am not as I appear. My name is Acridostrasz , though you may call me Acride. My Queen sent me here to stop Nefarian , and I will not rest until my task is complete. However, there are other foes here guarding his lair that I cannot take on alone. Help me dispose of them, and you will be in the favor of Alexstrasza . You may not know that name, but you will one day be thankful you do, of this I am certain.','Do not be alarmed. I am not as I appear. My name is Acridostrasz , though you may call me Acride. My Queen sent me here to stop Nefarian , and I will not rest until my task is complete. However, there are other foes here guarding his lair that I cannot take on alone. Help me dispose of them, and you will be in the favor of Alexstrasza . You may not know that name, but you will one day be thankful you do, of this I am certain.',0,0);
