INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000003,'Ok... let me explain Blackrock Spire right fast for the people having difficulty finding him. There are 2 different parts of (BRS)... there\'s Lower Blackrock Spire (LBRS) and Upper Blackrock Spire(UBRS). Lower blackrock spire has the troll boss, the spider boss, the ogres and wyrmkin. Upper blackrock spire has anvilcrack, rend, beast and Drak. You cannot get into UBRS without having the key provided by collecting all 4 gems from LBRS and forging them into the unadorned seal using Emberstrife\'s firebreath. Once you have the forged seal of ascension (a ring at this point), when you enter BRS, turn left up the steps of the crossing bridge in the main entrance room and you\'ll find a ramp leading up to a closed door. As you approach, if you have the seal, the fires on each side will ignite and the door to UBRS will open. If you see dragonkin, you\'re in the right place. Welcome to UBRS.','Ok... let me explain Blackrock Spire right fast for the people having difficulty finding him. There are 2 different parts of (BRS)... there\'s Lower Blackrock Spire (LBRS) and Upper Blackrock Spire(UBRS). Lower blackrock spire has the troll boss, the spider boss, the ogres and wyrmkin. Upper blackrock spire has anvilcrack, rend, beast and Drak. You cannot get into UBRS without having the key provided by collecting all 4 gems from LBRS and forging them into the unadorned seal using Emberstrife\'s firebreath. Once you have the forged seal of ascension (a ring at this point), when you enter BRS, turn left up the steps of the crossing bridge in the main entrance room and you\'ll find a ramp leading up to a closed door. As you approach, if you have the seal, the fires on each side will ignite and the door to UBRS will open. If you see dragonkin, you\'re in the right place. Welcome to UBRS.',0,0);
