INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000009,'I find it kind of lame how she is deep in contested territory (in PvP realms) close to the Barrens, while the Horde Counterpart is easily accessible to all Horde players in their own territory. I know Ally has advantages, it\'s just a pain to \'mount up\' on my 19 twink and hoof it ALL the way down there from Astranaar, ducking 30s and 40s, while they have nothing besides environment to worry about -_-','I find it kind of lame how she is deep in contested territory (in PvP realms) close to the Barrens, while the Horde Counterpart is easily accessible to all Horde players in their own territory. I know Ally has advantages, it\'s just a pain to \'mount up\' on my 19 twink and hoof it ALL the way down there from Astranaar, ducking 30s and 40s, while they have nothing besides environment to worry about -_-',0,0);
