INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000010,'Maedin says: Gral does love knowing things, almost as much as Torga loves his stories, and he\'s not as cranky as he seems. Folks would come from all around to share their experiences with him. Maedin says: When his temple was destroyed by the naga, this was the one place he couldn\'t go. He could feel the pain here... the loss... but the master of this place kept prying eyes out for so long. Maedin says: I knew someone had to be in this place, to remember and to learn what he could not.','Maedin says: Gral does love knowing things, almost as much as Torga loves his stories, and he\'s not as cranky as he seems. Folks would come from all around to share their experiences with him. Maedin says: When his temple was destroyed by the naga, this was the one place he couldn\'t go. He could feel the pain here... the loss... but the master of this place kept prying eyes out for so long. Maedin says: I knew someone had to be in this place, to remember and to learn what he could not.',0,0);
