INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000013,'Ol\' Griftah ain\'t never seen a place like dis before! <Griftah waves a hand at you, leaning in to whisper.> Shh! Keep it down! Dese brokers be offerin\' all kinda tings for us "mortals," and I be tryin\' ta find out just what dose tings be. Maybe ol\' Griftah be findin\' some new amulets ta sell, eh? Heh.','Ol\' Griftah ain\'t never seen a place like dis before! <Griftah waves a hand at you, leaning in to whisper.> Shh! Keep it down! Dese brokers be offerin\' all kinda tings for us "mortals," and I be tryin\' ta find out just what dose tings be. Maybe ol\' Griftah be findin\' some new amulets ta sell, eh? Heh.',0,0);
