INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000022,'While Lilleth sounds Hebrew-English, Radescu is a Romanian name 100%. Many common last names in Romania end in -escu as it is a patronymic. Kind of like how most Danish names end in -sen, Swedish end in -son, Polish end in -sky, but also work with prefix patronymic such as Irish O\'Riley or Scottish MacKenzie/McKenzie.','While Lilleth sounds Hebrew-English, Radescu is a Romanian name 100%. Many common last names in Romania end in -escu as it is a patronymic. Kind of like how most Danish names end in -sen, Swedish end in -son, Polish end in -sky, but also work with prefix patronymic such as Irish O\'Riley or Scottish MacKenzie/McKenzie.',0,0);
