INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000028,'You can tell a lot about a designer in how they weave their fabric together. Yours has the look of function over pride. Tightly sealed with mana infused right into the fabric. Impressive, though it could benefit from an artistic hand.','You can tell a lot about a designer in how they weave their fabric together. Yours has the look of function over pride. Tightly sealed with mana infused right into the fabric. Impressive, though it could benefit from an artistic hand.',0,0);
