INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000034,'In the current beta build, you get reputation from completing the story related exploration achievements. You seem to get a base amount of rep of 1920 per completed story achievement. You then get an item in your mail which will send you to Lorewalker Cho. He will then show you the story with a neat cinematic. As soon as you have completed a few of these achievements (2 or 3, think 2) you get access to one of the dailies. I\'ve only seen one daily so far, which required me to hand in 20 Mogu Archaeology Fragments. These are very easy to obtain on the beta as you collect about 30-40 per digsite. Reaching Friendly standing also seems to unlock Brann Bronzebeard as a vendor. He sells old Archaeology Fragments for completed Pandaria artifacts. He can also sell you an item which teleports you to the next Pandaria digsite and an item which randomizes your current Pandaria digsites.','In the current beta build, you get reputation from completing the story related exploration achievements. You seem to get a base amount of rep of 1920 per completed story achievement. You then get an item in your mail which will send you to Lorewalker Cho. He will then show you the story with a neat cinematic. As soon as you have completed a few of these achievements (2 or 3, think 2) you get access to one of the dailies. I\'ve only seen one daily so far, which required me to hand in 20 Mogu Archaeology Fragments. These are very easy to obtain on the beta as you collect about 30-40 per digsite. Reaching Friendly standing also seems to unlock Brann Bronzebeard as a vendor. He sells old Archaeology Fragments for completed Pandaria artifacts. He can also sell you an item which teleports you to the next Pandaria digsite and an item which randomizes your current Pandaria digsites.',0,0);
