INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000035,'•A new Seed has been added: Portal Shards •A mage who fell on hard times back in Dalaran has found a new home on Pandaria. Barnaby Fletcher will occasionally visit Halfhill Market to peddle a new type of seed – and take advantage of the Tillers’ hospitality. •Portal Shards grow into consumable items which can be used to open a portal from Sunsong Ranch to a major faction city.','•A new Seed has been added: Portal Shards •A mage who fell on hard times back in Dalaran has found a new home on Pandaria. Barnaby Fletcher will occasionally visit Halfhill Market to peddle a new type of seed – and take advantage of the Tillers’ hospitality. •Portal Shards grow into consumable items which can be used to open a portal from Sunsong Ranch to a major faction city.',0,0);
