INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000040,'Murg used to be a peon just like these orcs , but I got to be the best stone cracker out there! Now, they give Murg the name "Stonecrack" and lets me boss around these little guys. It\'s the best job, I tell ya!','Murg used to be a peon just like these orcs , but I got to be the best stone cracker out there! Now, they give Murg the name "Stonecrack" and lets me boss around these little guys. It\'s the best job, I tell ya!',0,0);
