INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000041,'Are you sure you want to buy th\'gear I\'ve got for sale? Crunchpaw has th\' best stuff these days. B\'tween the two of us, I heard she didn\'t get her nickname from fightin\' the Horde. Don\'t tell her I said that. Actually, I\'d prefer y\'din\'t even mention that we spoke. I\'m not on her good side right now.','Are you sure you want to buy th\'gear I\'ve got for sale? Crunchpaw has th\' best stuff these days. B\'tween the two of us, I heard she didn\'t get her nickname from fightin\' the Horde. Don\'t tell her I said that. Actually, I\'d prefer y\'din\'t even mention that we spoke. I\'m not on her good side right now.',0,0);
