INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000042,'Y\'should speak with Holly McTilla if you\'re lookin\' to square off against the best the Horde has to offer. Also, ask her who does her hair for me would ya?','Y\'should speak with Holly McTilla if you\'re lookin\' to square off against the best the Horde has to offer. Also, ask her who does her hair for me would ya?',0,0);
