INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000043,'I greet you, $C. We are the Order of the Awakened, and we represent the best interests of the arakkoa people. I am certain that you have witnessed the horrors brought upon the arakkoa and others by the Adherents of Rukhmar. We wish to reverse this damage and bring about a peaceful new era for our society. To do this, however, we require the knowledge of the Apexis. If you wish to assist us, we will trade valuable items for any Apexis relics you happen upon. What say you, $C?','I greet you, $C. We are the Order of the Awakened, and we represent the best interests of the arakkoa people. I am certain that you have witnessed the horrors brought upon the arakkoa and others by the Adherents of Rukhmar. We wish to reverse this damage and bring about a peaceful new era for our society. To do this, however, we require the knowledge of the Apexis. If you wish to assist us, we will trade valuable items for any Apexis relics you happen upon. What say you, $C?',0,0);
