INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000049,'I regrettably inform you that the finest arms and armaments for use in the field of battle are now sold by Ms. Crunchpaw. Don\'t worry, I\'m hard at work figuring out how to modify what I do have to be even better. I\'m thinking... extra arms! That you control with your mind!','I regrettably inform you that the finest arms and armaments for use in the field of battle are now sold by Ms. Crunchpaw. Don\'t worry, I\'m hard at work figuring out how to modify what I do have to be even better. I\'m thinking... extra arms! That you control with your mind!',0,0);
