INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000050,'I can\'t believe that peasant Holly McTilla was trusted with the finest weapons and armor. A dwarf! Honestly, it\'s no wonder we haven\'t taken this island yet.','I can\'t believe that peasant Holly McTilla was trusted with the finest weapons and armor. A dwarf! Honestly, it\'s no wonder we haven\'t taken this island yet.',0,0);
