INSERT IGNORE INTO `hotfixes`.`broadcast_text` (`ID`,`Text`,`Text1`,`LanguageID`,`VerifiedBuild`) VALUES (1000000051,'Yeah yeah, I know, my stuff isn\'t as good as what Tae\'lox is sellin\'. But ya know what, it\'s still prettier, right? Whaddaya mean you think it looks the same? It\'s CLEARLY different! You ungrateful bum! You\'re lucky my contract is still being enforced.','Yeah yeah, I know, my stuff isn\'t as good as what Tae\'lox is sellin\'. But ya know what, it\'s still prettier, right? Whaddaya mean you think it looks the same? It\'s CLEARLY different! You ungrateful bum! You\'re lucky my contract is still being enforced.',0,0);
